 *     use Nameable;
 *
 *     #[Label(\'Active Status\')]
 *     case ACTIVE = \'active\';
 *
 *     case INACTIVE = \'inactive\';
 * }
 *
 * Status::caseNames();  // Returns [\'ACTIVE\', \'INACTIVE\']
 * Status::names();      // Returns [\'Active Status\', \'Inactive\']
 * Status::names(true);  // Returns [\'ACTIVE\' => \'Active Status\', \'INACTIVE\' => \'Inactive\']
